  ('aboriginal-6f0ba476-moex-00150', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列關於公同共有之敘述，何者正確？', '["公同共有人得隨時請求分割公同共有物", "公同共有須有公同關係之存在", "公同共有具有應有部分", "公同共有人得自由處分公同共有物"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00151', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列關於未成年子女特有財產之敘述，何者錯誤？', '["未成年子女，因買賣而取得之財產，為其特有財產", "未成年子女，因繼承而取得之財產，為其特有財產", "未成年子女，因贈與而取得之財產，為其特有財產", "未成年子女，因其他無償取得之財產，為其特有財產"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00152', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列關於繼承效力之敘述，何者正確？', '["繼承人在繼承開始前 1 年內，從被繼承人之配偶受有不動產之贈與者，該財產視為已所得之 遺產", "被繼承人生前繼續扶養之人，應由親屬會議依其所受扶養之程度及其他關係，酌給遺產", "繼承人有數人時，在分割遺產前，各繼承人對於遺產之不動產為分別共有", "繼承人為被繼承人之直系血親卑親屬者，對於被繼承人之債務，應按被繼承人之遺囑償還之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00153', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '關於一定之數量，同時以文字及號碼表示，而其文字與號碼有不符合時，如法院不能決定何者為 當事人之原意，應以何者為準？', '["文字", "號碼", "最低額", "最高額"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00154', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲向乙承租獨立基地蓋房屋，關於基地與房屋，下列敘述，何者正確？', '["房屋為土地之部分", "房屋為獨立之不動產", "乙出賣土地，效力及於房屋", "甲出賣房屋，效力及於土地"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00155', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲、乙成立汽車買賣，但買受人乙得就A車或B車選擇其中一輛作為出賣人甲應交付之汽車。 交付前，該無權決定交付何種汽車標的之甲因過失造成A車毀損，甲欲交付B車於乙，但乙卻堅', '["甲、乙之間成立為選擇之債", "選擇之債數宗給付中，有 自始不能或嗣後不能給付者，債之關係僅存於餘存之給付者，所以僅存 B 車，乙不能選擇 A 車", "乙仍可以選擇A車，因為A車之毀損，係可歸責於甲", "乙選擇A車，但A車已經毀損，所 以為給付不能之情形，甲負給付不能之損害賠償責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00156', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '關於不動產登記，下列何者，為宣示登記？', '["移轉登記", "設定登記", "繼承登記", "抵押權次序拋棄登記"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00157', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲無權占有之古董花瓶，因天災而滅失時，就甲於占有期間為善意占有或惡意占有之情形，下列 敘述，何者正確？', '["無論甲為善意占有或惡意占有，皆不須對回復請求人負賠償責任", "無論甲為善意占有或惡意占有，皆須對回復請求人負賠償責任", "甲為善意占有人，因滅失受有利益，則應返還該所受利益與回復請求人；甲為惡意占有即須對 回復請求人負賠償責任", "甲為善意占有則無須對回復請求人負賠償責任，甲為惡意占有即須對回復請求人負賠償責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00158', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲將其所有之A地設定普通地上權於乙，乙在A地上建B屋，嗣丙無權占有該屋並設置C工廠， 該工廠之機器發出極大之噪音，而干擾丁所有之D鄰地之現使用人戊之日常生活安寧。下列關於 所有權妨害除去請求權之敘述，何者正確？', '["倘若戊係D鄰地之普通地上權人，則戊得向丙請求妨害之除去", "倘若戊係D鄰地之普通地上權人，則戊得向乙請求妨害之除去", "倘若戊係D鄰地之承租人，則丁得向乙請求妨害之除去", "倘若戊係D鄰地之無權占用人，則戊得向丙請求妨害之除去"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00159', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲男、乙女於民國（下同）108年6月間結婚，婚後1年，生一子A；甲於與乙之婚姻關係存續 中，自109年1月間起與丙女同居；111年1月28日，甲、丙生一女B。下列敘述，何者正確？', '["B為乙之非婚生子女", "如有事實足認甲為B之生父，乙得向甲提起認領之訴", "B與丙之關係，視為婚生子女，無須認領", "如有事實足認甲為B之生父，丙得向甲提起婚生否認之訴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
